// Prepare data for AI Agent analysis
const lowStockItems = $('Query ERP for low stock items').all();
const salesData = $('Fetch 90-day sales velocity data').all();

// Group sales by product
const salesByProduct = {};
salesData.forEach(sale => {
  if (!salesByProduct[sale.json.product_id]) {
    salesByProduct[sale.json.product_id] = [];
  }
  salesByProduct[sale.json.product_id].push({
    day: sale.json.day,
    dailySales: sale.json.daily_sales,
    avgDailySales: sale.json.avg_daily_sales
  });
});

// Create comprehensive dataset for AI
const inventoryAnalysis = lowStockItems.map(item => {
  const productSales = salesByProduct[item.json.product_id] || [];

  // Calculate basic metrics
  const totalSales90Days = productSales.reduce((sum, s) => sum + parseFloat(s.dailySales || 0), 0);
  const avgDailySales = totalSales90Days / 90;
  const salesVelocity = avgDailySales * 30; // Monthly velocity

  // Calculate trend (last 30 days vs previous 60 days)
  const recent30 = productSales.slice(0, 30).reduce((sum, s) => sum + parseFloat(s.dailySales || 0), 0) / 30;
  const previous60 = productSales.slice(30, 90).reduce((sum, s) => sum + parseFloat(s.dailySales || 0), 0) / 60;
  const trendPercentage = previous60 > 0 ? ((recent30 - previous60) / previous60 * 100).toFixed(2) : 0;

  return {
    productId: item.json.product_id,
    productName: item.json.product_name,
    sku: item.json.sku,
    category: item.json.category,
    currentStock: item.json.current_stock,
    reorderPoint: item.json.reorder_point,
    suggestedReorderQty: item.json.reorder_quantity,
    leadTimeDays: item.json.lead_time_days,
    supplierId: item.json.supplier_id,
    supplierName: item.json.supplier_name,
    supplierEmail: item.json.supplier_email,
    unitCost: item.json.unit_cost,
    lastPurchasePrice: item.json.last_purchase_price,
    salesMetrics: {
      avgDailySales: avgDailySales.toFixed(2),
      monthlyVelocity: salesVelocity.toFixed(2),
      total90DaySales: totalSales90Days,
      trendPercentage: trendPercentage,
      trendDirection: trendPercentage > 5 ? 'increasing' : trendPercentage < -5 ? 'decreasing' : 'stable'
    },
    stockoutRisk: calculateStockoutRisk(item.json.current_stock, avgDailySales, item.json.lead_time_days)
  };
});

function calculateStockoutRisk(currentStock, avgDailySales, leadTime) {
  const daysOfStock = avgDailySales > 0 ? currentStock / avgDailySales : 999;
  if (daysOfStock < leadTime) return 'CRITICAL';
  if (daysOfStock < leadTime * 1.5) return 'HIGH';
  if (daysOfStock < leadTime * 2) return 'MEDIUM';
  return 'LOW';
}

return {
  json: {
    analysisDate: new Date().toISOString(),
    totalLowStockItems: inventoryAnalysis.length,
    criticalItems: inventoryAnalysis.filter(i => i.stockoutRisk === 'CRITICAL').length,
    inventoryData: inventoryAnalysis
  }
};

// Parse AI Agent output
const agentOutput = $input.item.json.output || $input.item.json.text || $input.item.json;
let poData;

try {
  // Handle if output is string JSON
  if (typeof agentOutput === 'string') {
    const cleaned = agentOutput.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    poData = JSON.parse(cleaned);
  } else {
    poData = agentOutput;
  }
} catch (error) {
  throw new Error(`Failed to parse AI output: ${error.message}`);
}

if (!poData.purchaseOrders || !Array.isArray(poData.purchaseOrders)) {
  throw new Error('Invalid AI response structure');
}

// Add metadata
poData.generatedAt = new Date().toISOString();
poData.generatedBy = 'Mistral_AI_Agent';
poData.status = 'pending_approval';

return { json: poData };

// Generate supplier email for each PO
const poData = $('Parse and validate AI response').item.json;
const createdPOs = $('Insert approved POs into ERP database').all();

const emailsBySupplier = {};

// Group POs by supplier
poData.purchaseOrders.forEach((po, idx) => {
  if (!emailsBySupplier[po.supplierEmail]) {
    emailsBySupplier[po.supplierEmail] = {
      supplierName: po.supplierName,
      supplierId: po.supplierId,
      items: []
    };
  }

  emailsBySupplier[po.supplierEmail].items.push({
    poNumber: createdPOs[idx]?.json.po_number || `PO-${Date.now()}-${idx}`,
    productName: po.productName,
    sku: po.sku,
    quantity: po.recommendedOrderQty,
    unitCost: po.unitCost,
    totalCost: po.totalCost,
    priority: po.priority,
    expectedDelivery: po.expectedDeliveryDate,
    instructions: po.specialInstructions || 'Standard delivery'
  });
});

return Object.keys(emailsBySupplier).map(email => ({
  json: {
    supplierEmail: email,
    supplierName: emailsBySupplier[email].supplierName,
    supplierId: emailsBySupplier[email].supplierId,
    items: emailsBySupplier[email].items,
    totalItems: emailsBySupplier[email].items.length,
    totalCost: emailsBySupplier[email].items.reduce((sum, item) => sum + item.totalCost, 0).toFixed(2)
  }
}));
